        fold_regions(tcx, self.inner, |r, depth| match r.kind() {
            ty::ReBound(ty::BoundVarIndexKind::Bound(debruijn), br) => {
                debug_assert_eq!(debruijn, depth);
                map(ty::RegionVid::from_usize(br.var.index()))
            }
            _ => bug!("unexpected region {r:?}"),
        })
    }
