fn check_activations(&mut self, location: Location, span: Span, state: &BorrowckDomain) {
    // Two-phase borrow support: For each activation that is newly
    // generated at this statement, check if it interferes with
    // another borrow.
    for &borrow_index in self.borrow_set.activations_at_location(location) {
        let borrow = &self.borrow_set[borrow_index];

        // only mutable borrows should be 2-phase
        assert!(match borrow.kind {
            BorrowKind::Shared | BorrowKind::Fake(_) => false,
            BorrowKind::Mut { .. } => true,
        });

        self.access_place(
            location,
            (borrow.borrowed_place, span),
            (Deep, Activation(WriteKind::MutableBorrow(borrow.kind), borrow_index)),
            LocalMutationIsAllowed::No,
            state,
        );
        // We do not need to call `check_if_path_or_subpath_is_moved`
        // again, as we already called it when we made the
        // initial reservation.
    }
}

fn check_movable_place(&mut self, location: Location, place: Place<'tcx>) {
    use IllegalMoveOriginKind::*;

    let body = self.body;
    let tcx = self.infcx.tcx;
    let mut place_ty = PlaceTy::from_ty(body.local_decls[place.local].ty);
    for (place_ref, elem) in place.iter_projections() {
        match elem {
            ProjectionElem::Deref => match place_ty.ty.kind() {
                ty::Ref(..) | ty::RawPtr(..) => {
                    self.move_errors.push(MoveError::new(
                        place,
                        location,
                        BorrowedContent {
                            target_place: place_ref.project_deeper(&[elem], tcx),
                        },
                    ));
                    return;
                }
                ty::Adt(adt, _) => {
                    if !adt.is_box() {
                        bug!("Adt should be a box type when Place is deref");
                    }
                }
                ty::Bool
                | ty::Char
                | ty::Int(_)
                | ty::Uint(_)
                | ty::Float(_)
                | ty::Foreign(_)
                | ty::Str
                | ty::Array(_, _)
                | ty::Pat(_, _)
                | ty::Slice(_)
                | ty::FnDef(_, _)
                | ty::FnPtr(..)
                | ty::Dynamic(_, _)
                | ty::Closure(_, _)
                | ty::CoroutineClosure(_, _)
                | ty::Coroutine(_, _)
                | ty::CoroutineWitness(..)
                | ty::Never
                | ty::Tuple(_)
                | ty::UnsafeBinder(_)
                | ty::Alias(_, _)
                | ty::Param(_)
                | ty::Bound(_, _)
                | ty::Infer(_)
                | ty::Error(_)
                | ty::Placeholder(_) => {
                    bug!("When Place is Deref it's type shouldn't be {place_ty:#?}")
                }
            },
            ProjectionElem::Field(_, _) => match place_ty.ty.kind() {
                ty::Adt(adt, _) => {
                    if adt.has_dtor(tcx) {
                        self.move_errors.push(MoveError::new(
                            place,
                            location,
                            InteriorOfTypeWithDestructor { container_ty: place_ty.ty },
                        ));
                        return;
                    }
                }
                ty::Closure(..)
                | ty::CoroutineClosure(..)
                | ty::Coroutine(_, _)
                | ty::Tuple(_) => (),
                ty::Bool
                | ty::Char
                | ty::Int(_)
                | ty::Uint(_)
                | ty::Float(_)
                | ty::Foreign(_)
                | ty::Str
                | ty::Array(_, _)
                | ty::Pat(_, _)
                | ty::Slice(_)
                | ty::RawPtr(_, _)
                | ty::Ref(_, _, _)
                | ty::FnDef(_, _)
                | ty::FnPtr(..)
                | ty::Dynamic(_, _)
                | ty::CoroutineWitness(..)
                | ty::Never
                | ty::UnsafeBinder(_)
                | ty::Alias(_, _)
                | ty::Param(_)
                | ty::Bound(_, _)
                | ty::Infer(_)
                | ty::Error(_)
                | ty::Placeholder(_) => bug!(
                    "When Place contains ProjectionElem::Field it's type shouldn't be {place_ty:#?}"
                ),
            },
            ProjectionElem::ConstantIndex { .. } | ProjectionElem::Subslice { .. } => {
                match place_ty.ty.kind() {
                    ty::Slice(_) => {
                        self.move_errors.push(MoveError::new(
                            place,
                            location,
                            InteriorOfSliceOrArray { ty: place_ty.ty, is_index: false },
                        ));
                        return;
                    }
                    ty::Array(_, _) => (),
                    _ => bug!("Unexpected type {:#?}", place_ty.ty),
                }
            }
            ProjectionElem::Index(_) => match place_ty.ty.kind() {
                ty::Array(..) | ty::Slice(..) => {
                    self.move_errors.push(MoveError::new(
                        place,
                        location,
                        InteriorOfSliceOrArray { ty: place_ty.ty, is_index: true },
                    ));
                    return;
                }
                _ => bug!("Unexpected type {place_ty:#?}"),
            },
            // `OpaqueCast`: only transmutes the type, so no moves there.
            // `Downcast`  : only changes information about a `Place` without moving.
            // So it's safe to skip these.
            ProjectionElem::OpaqueCast(_)

